# @cctt_verify {"v":2,"sym":"sympy.matrices.tests.test_matrices.test_jacobian_metrics","kind":"function","src_hash":"4417bd5ca3539f23","in":{"base":"Any"},"out":{"base":"Any","pred":"result satisfies: J == X.jacobian(Y.T) and J == X.T.jacobian(Y) and J == X.T.jacobian(Y.T) and g == Matrix([[1, 0], [0, rho ** 2]])"},"spec":{"lhs":"test_jacobian_metrics()","rhs":"J == X.jacobian(Y.T) and J == X.T.jacobian(Y) and J == X.T.jacobian(Y.T) and g == Matrix([[1, 0], [0, rho ** 2]])","over":{"base":"Any"},"name":"test_jacobian_metrics_correct"},"guarantee":"J == X.jacobian(Y.T); J == X.T.jacobian(Y); J == X.T.jacobian(Y.T)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.matrices.tests.test_matrices.test_jacobian_metrics_correct","statement":"Path(test_jacobian_metrics(x), J == X.jacobian(Y.T); J == X.T.jacobian(Y); J == X.T.jacobian(Y.T))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c722a46970aa34b9","spec_source":"static","formal_spec":{"source":"static","strength":"formal","ensures":["J == X.jacobian(Y.T)","J == X.T.jacobian(Y)","J == X.T.jacobian(Y.T)","g == Matrix([[1, 0], [0, rho ** 2]])"],"pure":true},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.2,"verdict_class":"assumed","binding":true}}
def test_jacobian_metrics():
    rho, phi = symbols("rho,phi")
    X = Matrix([rho*cos(phi), rho*sin(phi)])
    Y = Matrix([rho, phi])
    J = X.jacobian(Y)
    assert J == X.jacobian(Y.T)
    assert J == (X.T).jacobian(Y)
    assert J == (X.T).jacobian(Y.T)
    g = J.T*eye(J.shape[0])*J
    g = g.applyfunc(trigsimp)
    assert g == Matrix([[1, 0], [0, rho**2]])


